package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Field;
import java.util.LinkedHashMap;
import java.util.Map;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVParserTest {

    private CSVParser parser;

    @BeforeEach
    void setUp() throws Exception {
        CSVFormat format = mock(CSVFormat.class);

        // Use reflection to instantiate CSVParser without calling constructor that sets final fields
        // Because headerMap is final, we need to create a subclass or use Unsafe or ReflectionFactory
        // Here, we use the public constructor but to avoid NPEs, mock the format and pass empty reader
        parser = new CSVParser(new java.io.StringReader(""), format);

        // Use reflection to set the final 'headerMap' field to a non-null default map to avoid NPE in getHeaderMap()
        Field headerMapField = CSVParser.class.getDeclaredField("headerMap");
        headerMapField.setAccessible(true);
        // Set to empty map by default to avoid NPE from final field
        headerMapField.set(parser, new LinkedHashMap<String, Integer>());
    }

    @Test
    void testGetHeaderMap_whenHeaderMapIsNull() throws Exception {
        Field headerMapField = CSVParser.class.getDeclaredField("headerMap");
        headerMapField.setAccessible(true);

        // Remove final modifier via reflection to set null
        setFinalField(headerMapField, parser, null);

        Map<String, Integer> result = parser.getHeaderMap();
        assertNull(result, "Expected null when headerMap field is null");
    }

    @Test
    void testGetHeaderMap_whenHeaderMapIsNotNull() throws Exception {
        LinkedHashMap<String, Integer> originalMap = new LinkedHashMap<>();
        originalMap.put("col1", 0);
        originalMap.put("col2", 1);

        Field headerMapField = CSVParser.class.getDeclaredField("headerMap");
        headerMapField.setAccessible(true);

        setFinalField(headerMapField, parser, originalMap);

        Map<String, Integer> result = parser.getHeaderMap();

        assertNotNull(result, "Expected non-null map when headerMap field is set");
        assertEquals(originalMap.size(), result.size(), "Map size should be equal");
        assertEquals(originalMap, result, "Returned map should be equal to original");
        assertNotSame(originalMap, result, "Returned map should be a new instance");
    }

    // Helper method to set final fields via reflection
    private static void setFinalField(Field field, Object target, Object value) throws Exception {
        field.setAccessible(true);

        // Remove final modifier from field (Java 8+)
        Field modifiersField = Field.class.getDeclaredField("modifiers");
        modifiersField.setAccessible(true);
        modifiersField.setInt(field, field.getModifiers() & ~java.lang.reflect.Modifier.FINAL);

        field.set(target, value);
    }
}
